css:
/* Header Base Styles */
.site-header {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 1000;
  background: rgba(255, 255, 255, 0.85);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border-bottom: 1px solid rgba(0, 0, 0, 0.08);
}

.header-inner {
  max-width: 1000px;
  margin: 0 auto;
  padding: 0 20px;
  height: 60px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.header-logo {
  font-size: 1.2rem;
  font-weight: 800;
  color: #c2410c;
  text-decoration: none;
}

/* Desktop Nav */
.site-nav ul {
  list-style: none;
  display: flex;
  gap: 24px;
  margin: 0;
  padding: 0;
}

.site-nav a {
  text-decoration: none;
  color: #4b5563;
  font-weight: 600;
  font-size: 0.9rem;
  transition: color 0.2s;
}

.site-nav a:hover { color: #f97316; }
.site-nav .active a { color: #f97316; }

/* Mobile Menu Button - Hidden by default */
.hamb-btn {
  display: none;
  width: 36px;
  height: 36px;
  background: none;
  border: none;
  position: relative;
  cursor: pointer;
  z-index: 1100;
}

.hamb-line, .hamb-line::before, .hamb-line::after {
  display: block;
  width: 22px;
  height: 2px;
  background: #4b5563;
  border-radius: 2px;
  transition: all 0.3s ease;
}

.hamb-line::before, .hamb-line::after { content: ''; position: absolute; left: 0; }
.hamb-line::before { top: -6px; }
.hamb-line::after { top: 6px; }

.hamb-btn.active .hamb-line { background: transparent; }
.hamb-btn.active .hamb-line::before { transform: rotate(45deg); top: 0; }
.hamb-btn.active .hamb-line::after { transform: rotate(-45deg); top: 0; }

/* Mobile Layout Styles */
@media (max-width: 768px) {
  .hamb-btn { display: block; }

  .site-nav {
    position: fixed;
    top: 0;
    right: -100%;
    width: 260px;
    height: 100vh;
    background: #fff;
    padding-top: 80px;
    box-shadow: -10px 0 20px rgba(0,0,0,0.05);
    transition: right 0.3s ease-in-out;
    z-index: 1001;
  }

  .site-nav.open { right: 0; }

  .site-nav ul {
    flex-direction: column;
    gap: 0;
  }

  .site-nav li a {
    display: block;
    padding: 16px 24px;
    border-bottom: 1px solid #f9fafb;
  }
}
